function JSONBinaryDecode(t){const e=new DataView(t),n=new TextDecoder,i=e.getUint32(0,!1),r=JSON.parse(n.decode(new Uint8Array(t,4,i)));return function t(e,n){for(let i in n){let r=n[i];if("string"==typeof r&&r.startsWith("SlNPTkJJT")){r=atob(r);if(r.startsWith("JSONBIN:")){const t=Uint8Array.from(r,t=>t.charCodeAt(0)).buffer,a=new DataView(t).getUint32(8,!1),o=new DataView(t).getUint32(12,!1);n[i]=new Uint8Array(e.slice(a,a+o))}}else null!==r&&"object"==typeof r&&t(e,r)}}(t,r),r}